/*Table structure for table `product` */

DROP TABLE IF EXISTS `product`;

CREATE TABLE `product` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `category_id` int(11) NOT NULL COMMENT '所属分类ID',
  `name` varchar(200) NOT NULL COMMENT '商品名称',
  `price` decimal(10,2) NOT NULL COMMENT '售价',
  `stock` int(11) NOT NULL COMMENT '库存数量',
  `specification` varchar(100) DEFAULT NULL COMMENT '规格/重量',
  `image_url` mediumtext,
  `description` text COMMENT '商品详细描述',
  `origin` varchar(100) DEFAULT NULL,
  `shelf_life` varchar(100) DEFAULT NULL,
  `storage_method` varchar(100) DEFAULT NULL,
  `delivery_info` varchar(200) DEFAULT NULL,
  `sales` int(11) DEFAULT '0' COMMENT '销量（用于推荐排序）',
  `status` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_category_id` (`category_id`),
  KEY `idx_name` (`name`),
  KEY `idx_sales` (`sales`),
  CONSTRAINT `fk_product_category` FOREIGN KEY (`category_id`) REFERENCES `category` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COMMENT='商品表';

